// server/cardImage.js — Pure geometric stamps, no fonts needed
const STAMPS_FOR_REWARD = 10;
const NAVY = '#1a1e5a';
const ORANGE = '#e8461e';

const FOX_B64 = '';

// Pure SVG geometric stamp — no text, no font
// Style: Japanese hanko — concentric dashed rings + unique inner pattern per number
function stampSVG(cx, cy, r, index, filled) {
  if (!filled) {
    return `<circle cx="${cx}" cy="${cy}" r="${r-2}" fill="none" stroke="rgba(255,255,255,0.1)" stroke-width="1.5" stroke-dasharray="6 4"/>`;
  }

  const isTen = index === 9;
  const innerR = Math.round(r * 0.62);
  const dotR = Math.round(r * 0.08);

  // Each stamp has a unique inner pattern based on its number
  // Using dots arranged in patterns like dice/domino — universally readable
  const patterns = [
    // 1: single center dot
    `<circle cx="${cx}" cy="${cy}" r="${dotR*2.2}" fill="${ORANGE}"/>`,
    // 2: two dots horizontal
    `<circle cx="${cx-innerR*0.35}" cy="${cy}" r="${dotR*1.8}" fill="${ORANGE}"/>
     <circle cx="${cx+innerR*0.35}" cy="${cy}" r="${dotR*1.8}" fill="${ORANGE}"/>`,
    // 3: triangle
    `<circle cx="${cx}" cy="${cy-innerR*0.38}" r="${dotR*1.6}" fill="${ORANGE}"/>
     <circle cx="${cx-innerR*0.35}" cy="${cy+innerR*0.22}" r="${dotR*1.6}" fill="${ORANGE}"/>
     <circle cx="${cx+innerR*0.35}" cy="${cy+innerR*0.22}" r="${dotR*1.6}" fill="${ORANGE}"/>`,
    // 4: four corners
    `<circle cx="${cx-innerR*0.32}" cy="${cy-innerR*0.32}" r="${dotR*1.5}" fill="${ORANGE}"/>
     <circle cx="${cx+innerR*0.32}" cy="${cy-innerR*0.32}" r="${dotR*1.5}" fill="${ORANGE}"/>
     <circle cx="${cx-innerR*0.32}" cy="${cy+innerR*0.32}" r="${dotR*1.5}" fill="${ORANGE}"/>
     <circle cx="${cx+innerR*0.32}" cy="${cy+innerR*0.32}" r="${dotR*1.5}" fill="${ORANGE}"/>`,
    // 5: four corners + center
    `<circle cx="${cx-innerR*0.32}" cy="${cy-innerR*0.32}" r="${dotR*1.4}" fill="${ORANGE}"/>
     <circle cx="${cx+innerR*0.32}" cy="${cy-innerR*0.32}" r="${dotR*1.4}" fill="${ORANGE}"/>
     <circle cx="${cx}" cy="${cy}" r="${dotR*1.4}" fill="${ORANGE}"/>
     <circle cx="${cx-innerR*0.32}" cy="${cy+innerR*0.32}" r="${dotR*1.4}" fill="${ORANGE}"/>
     <circle cx="${cx+innerR*0.32}" cy="${cy+innerR*0.32}" r="${dotR*1.4}" fill="${ORANGE}"/>`,
    // 6: six dots (2 columns of 3)
    `<circle cx="${cx-innerR*0.3}" cy="${cy-innerR*0.38}" r="${dotR*1.3}" fill="${ORANGE}"/>
     <circle cx="${cx+innerR*0.3}" cy="${cy-innerR*0.38}" r="${dotR*1.3}" fill="${ORANGE}"/>
     <circle cx="${cx-innerR*0.3}" cy="${cy}" r="${dotR*1.3}" fill="${ORANGE}"/>
     <circle cx="${cx+innerR*0.3}" cy="${cy}" r="${dotR*1.3}" fill="${ORANGE}"/>
     <circle cx="${cx-innerR*0.3}" cy="${cy+innerR*0.38}" r="${dotR*1.3}" fill="${ORANGE}"/>
     <circle cx="${cx+innerR*0.3}" cy="${cy+innerR*0.38}" r="${dotR*1.3}" fill="${ORANGE}"/>`,
    // 7: ring of 6 + center
    ...[7,8,9].map((n,i) => {
      const count = n;
      let dots = '';
      for(let d=0; d<count; d++) {
        const angle = (d * 2 * Math.PI / count) - Math.PI/2;
        const dr = innerR * 0.38;
        const dx = cx + Math.round(dr * Math.cos(angle));
        const dy = cy + Math.round(dr * Math.sin(angle));
        dots += `<circle cx="${dx}" cy="${dy}" r="${dotR*1.2}" fill="${ORANGE}"/>`;
      }
      return dots;
    })
  ];

  const innerFill = isTen ? 'rgba(232,70,30,0.15)' : 'rgba(232,70,30,0.07)';
  const outerStroke = isTen ? '3.5' : '2.5';
  const outerDash = isTen ? '' : 'stroke-dasharray="12 3"';

  return `
  <g filter="url(#ink)">
    <circle cx="${cx}" cy="${cy}" r="${r-2}" fill="${innerFill}" stroke="${ORANGE}" stroke-width="${outerStroke}" ${outerDash}/>
    <circle cx="${cx}" cy="${cy}" r="${innerR}" fill="rgba(232,70,30,0.04)" stroke="${ORANGE}" stroke-width="1.5" stroke-dasharray="7 4"/>
    ${patterns[index] || patterns[0]}
  </g>`;
}

function generateCardSVG(stamps = 0, cardId = '') {
  const W = 1032, H = 336;
  const stampR = 34, stampGap = 16, cols = 5;
  const totalW = cols*(stampR*2) + (cols-1)*stampGap;
  const foxW = 210;
  const contentX = foxW + 30;
  const startX = contentX + Math.round((W - contentX - 20 - totalW) / 2);
  const startY = 20;

  let stampsHTML = '';
  for (let i = 0; i < STAMPS_FOR_REWARD; i++) {
    const col = i % cols;
    const row = Math.floor(i / cols);
    const cx = startX + col*(stampR*2+stampGap) + stampR;
    const cy = startY + row*(stampR*2+stampGap+8) + stampR;
    stampsHTML += stampSVG(cx, cy, stampR, i, i < stamps);
  }

  const barY = startY + 2*(stampR*2+stampGap+8) + 10;
  const barW = totalW, barX = startX;
  const fillW = Math.round(barW * stamps / STAMPS_FOR_REWARD);
  const remaining = STAMPS_FOR_REWARD - stamps;
  const rewardText = stamps >= STAMPS_FOR_REWARD
    ? 'RAMEN OFFERT — Montre ta carte !'
    : `encore ${remaining} tampon${remaining>1?'s':''} pour ton ramen`;

  const shortId = cardId ? cardId.substring(0,8).toUpperCase() : '';

  return `<?xml version="1.0" encoding="UTF-8"?>
<svg width="${W}" height="${H}" viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <pattern id="dots" x="0" y="0" width="16" height="16" patternUnits="userSpaceOnUse">
      <circle cx="8" cy="8" r="1.5" fill="rgba(232,70,30,0.11)"/>
    </pattern>
    <linearGradient id="barGrad" x1="0" y1="0" x2="1" y2="0">
      <stop offset="0%" stop-color="${ORANGE}"/>
      <stop offset="100%" stop-color="#ff9060"/>
    </linearGradient>
    <filter id="ink" x="-20%" y="-20%" width="140%" height="140%">
      <feTurbulence type="fractalNoise" baseFrequency="0.85" numOctaves="4" result="noise"/>
      <feDisplacementMap in="SourceGraphic" in2="noise" scale="2" xChannelSelector="R" yChannelSelector="G"/>
    </filter>
    <clipPath id="foxClip">
      <ellipse cx="105" cy="${H/2}" rx="100" ry="110"/>
    </clipPath>
  </defs>
  <rect width="${W}" height="${H}" fill="${NAVY}"/>
  <rect width="${W}" height="${H}" fill="url(#dots)"/>
  <ellipse cx="105" cy="${H/2}" rx="108" ry="118" fill="rgba(232,70,30,0.05)"/>
  <image href="data:image/png;base64,${FOX_B64}"
    x="5" y="${Math.round(H/2-112)}" width="200" height="224"
    clip-path="url(#foxClip)" preserveAspectRatio="xMidYMid meet"/>
  ${stampsHTML}
  <rect x="${barX}" y="${barY}" width="${barW}" height="3" rx="1.5" fill="rgba(255,255,255,0.08)"/>
  ${fillW>0?`<rect x="${barX}" y="${barY}" width="${fillW}" height="3" rx="1.5" fill="url(#barGrad)"/>`:''}
  <text x="${barX}" y="${barY+20}" font-family="Arial,sans-serif" font-size="15" font-weight="bold" fill="${ORANGE}">${stamps} / ${STAMPS_FOR_REWARD} — ${rewardText}</text>
  <text x="${W/2}" y="${H-8}" text-anchor="middle" font-family="monospace" font-size="10" fill="rgba(255,255,255,0.15)">${shortId}</text>
</svg>`;
}

module.exports = { generateCardSVG };
